import React, { useCallback, useMemo } from 'react';
import {
  StyleSheet,
  Text,
  TouchableOpacity,
  View
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useMessageStore } from '../hooks/useMessageStore';
import { ChatInput } from './ChatInput';
import { ChatKeyboardProvider, useChatKeyboard } from './ChatKeyboard';
import { ChatList } from './ChatList';
import { ChatMenu } from './ChatMenu';
import { ChatStateProvider, useChatState } from './ChatState';
import { ChatThemeProvider, useChatTheme } from './ChatTheme';

interface ChatCoreProps {
  // Минимальные пропсы для изоляции
  onSendMessage?: (text: string) => void;
  onError?: (error: Error) => void;
  isBotEnabled?: boolean;
  onToggleBot?: () => void;
}

// Внутренний компонент с логикой
const ChatCoreInner: React.FC<ChatCoreProps> = React.memo(({ onSendMessage, onError, isBotEnabled = false, onToggleBot }) => {
  // Подключаем Zustand store для сообщений
  const messages = useMessageStore((s) => s.messages);
  const addMessage = useMessageStore((s) => s.addMessage);

  // Используем провайдеры
  const { 
    inputText, 
    setInputText, 
    inputFocused, 
    setInputFocused,
    showMenu,
    setShowMenu,
    isSearching,
    setIsSearching,
    searchQuery,
    setSearchQuery,
    showThemeSelector,
    setShowThemeSelector
  } = useChatState();

  const { currentThemeData, createThemedStyles } = useChatTheme();
  const { keyboardHeight } = useChatKeyboard();

  // Отфильтрованные сообщения для правильного порядка (при inverted={true} нужен обратный порядок)
  const filteredMessages = useMemo(() => {
    try {
      return [...messages].reverse();
    } catch (error) {
      console.error('ChatCore: Ошибка фильтрации сообщений', error);
      return [];
    }
  }, [messages]);

  // Создаем themedStyles используя провайдер
  const themedStyles = useMemo(() => {
    try {
      return createThemedStyles(keyboardHeight);
    } catch (error) {
      console.error('ChatCore: Ошибка создания стилей', error);
      return {};
    }
  }, [createThemedStyles, keyboardHeight]);

  // Безопасная обработка ошибок - мемоизирована
  const safeExecute = useCallback((fn: () => void, errorMessage: string) => {
    try {
      fn();
    } catch (error) {
      console.error(`ChatCore Error: ${errorMessage}`, error);
      onError?.(error as Error);
    }
  }, [onError]);

  // Безопасная установка состояния - мемоизирована
  const safeSetState = useCallback((setter: (value: any) => void, value: any, errorMessage: string) => {
    try {
      setter(value);
    } catch (error) {
      console.error(`ChatCore Error: ${errorMessage}`, error);
      onError?.(error as Error);
    }
  }, [onError]);

  // Безопасная обработка отправки сообщения
  const handleSendMessage = useCallback(() => {
    safeExecute(() => {
      if (inputText.trim()) {
        addMessage(inputText.trim());
        setInputText("");
        onSendMessage?.(inputText.trim());
      }
    }, 'sendMessage');
  }, [inputText, addMessage, setInputText, onSendMessage, safeExecute]);

  // Безопасная обработка переключения меню
  const handleMenuToggle = useCallback(() => {
    safeExecute(() => {
      setShowMenu(!showMenu);
    }, 'toggleMenu');
  }, [showMenu, setShowMenu, safeExecute]);

  // Безопасная обработка переключения поиска
  const handleSearchToggle = useCallback(() => {
    safeExecute(() => {
      setIsSearching(!isSearching);
      if (isSearching) {
        setSearchQuery("");
      }
    }, 'toggleSearch');
  }, [isSearching, setIsSearching, setSearchQuery, safeExecute]);

  // Безопасная обработка переключения тем
  const handleThemeToggle = useCallback(() => {
    safeExecute(() => {
      setShowThemeSelector(!showThemeSelector);
      setShowMenu(false);
    }, 'toggleThemeSelector');
  }, [showThemeSelector, setShowThemeSelector, setShowMenu, safeExecute]);

  // Безопасная обработка бота
  const handleBotToggle = useCallback(() => {
    safeExecute(() => {
      onToggleBot?.();
      setShowMenu(false);
    }, 'toggleBot');
  }, [onToggleBot, setShowMenu, safeExecute]);

  // Безопасная обработка закрытия поиска
  const handleSearchClose = useCallback(() => {
    safeExecute(() => {
      setIsSearching(false);
      setSearchQuery("");
    }, 'closeSearch');
  }, [setIsSearching, setSearchQuery, safeExecute]);

  // Безопасная обработка закрытия тем
  const handleThemeClose = useCallback(() => {
    safeExecute(() => {
      setShowThemeSelector(false);
    }, 'closeThemeSelector');
  }, [setShowThemeSelector, safeExecute]);

  // Безопасная обработка выбора темы
  const handleThemeSelect = useCallback((theme: string) => {
    safeExecute(() => {
      // Здесь нужно будет добавить логику изменения темы
      setShowThemeSelector(false);
    }, 'selectTheme');
  }, [setShowThemeSelector, safeExecute]);

  // Fallback UI при ошибках
  if (!messages) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.fallbackContainer}>
          <Text style={styles.fallbackText}>Загрузка сообщений...</Text>
        </View>
      </SafeAreaView>
    );
  }

  try {
    return (
      <SafeAreaView style={[styles.container, themedStyles.safe]}>
        <View style={[styles.container, themedStyles.safe]}>
          {/* Заголовок и меню */}
          <ChatMenu
            showMenu={showMenu}
            isSearching={isSearching}
            searchQuery={searchQuery}
            showThemeSelector={showThemeSelector}
            isBotEnabled={isBotEnabled}
            onMenuToggle={handleMenuToggle}
            onSearchToggle={handleSearchToggle}
            onSearchClose={handleSearchClose}
            onSearchChange={setSearchQuery}
            onThemeToggle={handleThemeToggle}
            onBotToggle={handleBotToggle}
            themedStyles={themedStyles}
          />

          {/* Обработчик клика вне меню */}
          {showMenu && (
            <TouchableOpacity
              style={styles.menuBackdrop}
              onPress={() => setShowMenu(false)}
              activeOpacity={1}
            />
          )}

          {/* Список сообщений */}
          <ChatList
            messages={filteredMessages}
            onSendMessage={handleSendMessage}
            onError={onError}
            themedStyles={themedStyles}
            styles={styles}
            currentThemeData={currentThemeData}
          />

          {/* Поле ввода */}
          <ChatInput
            inputText={inputText}
            setInputText={setInputText}
            onSendMessage={handleSendMessage}
            keyboardHeight={keyboardHeight}
            currentThemeData={currentThemeData}
            inputFocused={inputFocused}
            setInputFocused={setInputFocused}
          />

          {/* Селектор тем */}
          {showThemeSelector && (() => {
            try {
              return (
                <TouchableOpacity 
                  style={styles.themeOverlay}
                  onPress={handleThemeClose}
                  activeOpacity={1}
                >
                  <TouchableOpacity 
                    style={styles.themeContent}
                    onPress={() => {}}
                    activeOpacity={1}
                  >
                    <Text style={styles.themeTitle}>Выберите тему</Text>
                    {/* Здесь будет список тем */}
                  </TouchableOpacity>
                </TouchableOpacity>
              );
            } catch (error) {
              console.error('ChatCore: Ошибка рендеринга селектора тем', error);
              return null;
            }
          })()}
        </View>
      </SafeAreaView>
    );
  } catch (error) {
    console.error('ChatCore: Критическая ошибка рендеринга', error);
    onError?.(error as Error);
    return (
      <SafeAreaView style={styles.fallbackContainer}>
        <Text style={styles.fallbackText}>
          Произошла ошибка. Попробуйте перезапустить приложение.
        </Text>
      </SafeAreaView>
    );
  }
});

ChatCoreInner.displayName = 'ChatCoreInner';

// Обертка с провайдерами
