import { Ionicons } from '@expo/vector-icons';
import React, { useCallback } from 'react';
import { StyleSheet, Text, TextInput, TouchableOpacity, View } from 'react-native';

interface ChatMenuProps {
  showMenu: boolean;
  isSearching: boolean;
  searchQuery: string;
  showThemeSelector: boolean;
  isBotEnabled: boolean;
  onMenuToggle: () => void;
  onSearchToggle: () => void;
  onSearchClose: () => void;
  onSearchChange: (text: string) => void;
  onThemeToggle: () => void;
  onBotToggle: () => void;
  themedStyles: {
    header: any;
    headerText: any;
  };
}

export const ChatMenu: React.FC<ChatMenuProps> = React.memo(({
  showMenu,
  isSearching,
  searchQuery,
  showThemeSelector,
  isBotEnabled,
  onMenuToggle,
  onSearchToggle,
  onSearchClose,
  onSearchChange,
  onThemeToggle,
  onBotToggle,
  themedStyles
}) => {
  const handleMenuToggle = useCallback(() => {
    try {
      onMenuToggle();
    } catch (error) {
      console.error('ChatMenu: Ошибка переключения меню', error);
    }
  }, [onMenuToggle]);

  const handleSearchToggle = useCallback(() => {
    try {
      onSearchToggle();
    } catch (error) {
      console.error('ChatMenu: Ошибка переключения поиска', error);
    }
  }, [onSearchToggle]);

  const handleThemeToggle = useCallback(() => {
    try {
      onThemeToggle();
    } catch (error) {
      console.error('ChatMenu: Ошибка переключения тем', error);
    }
  }, [onThemeToggle]);

  const handleBotToggle = useCallback(() => {
    try {
      onBotToggle();
    } catch (error) {
      console.error('ChatMenu: Ошибка переключения бота', error);
    }
  }, [onBotToggle]);

  return (
    <>
      <View style={[styles.header, themedStyles.header]}>
        {!isSearching ? (
          <>
            <Text style={[styles.headerText, themedStyles.headerText]}>Axora Chat</Text>
            <TouchableOpacity
              style={styles.menuButton}
              onPress={handleMenuToggle}
              activeOpacity={0.7}
            >
              <Ionicons name="menu" size={24} color="#fff" />
            </TouchableOpacity>
          </>
        ) : (
          <View style={styles.searchContainer}>
            <TextInput
              style={styles.searchInput}
              value={searchQuery}
              onChangeText={onSearchChange}
              placeholder="Поиск сообщений..."
              placeholderTextColor="#888"
              autoFocus
              returnKeyType="search"
            />
            <TouchableOpacity 
              style={styles.searchCloseButton}
              onPress={onSearchClose}
              activeOpacity={0.7}
            >
              <Ionicons name="close" size={20} color="#fff" />
            </TouchableOpacity>
          </View>
        )}
      </View>

      {/* Модальное окно меню */}
      {showMenu && (
        <TouchableOpacity 
          style={styles.menuOverlay}
          onPress={handleMenuToggle}
          activeOpacity={1}
        >
          <TouchableOpacity 
            style={styles.menuContent}
            onPress={() => {}}
            activeOpacity={1}
          >
            <TouchableOpacity 
              style={styles.menuItem}
